func lifecycleLabel(l string) string {
	switch l {
	case "spawning":
		return "spawning"
	case "working":
		return "working"
	case "idle":
		return "idle"
	case "killed":
		return "killed"
	}
	return "—"
}

func lifecycleTooltip(l string, pid int) string {
	switch l {
	case "spawning":
		return fmt.Sprintf("subprocess starting (pid %d)", pid)
	case "working":
		return fmt.Sprintf("processing turn (pid %d)", pid)
	case "idle":
		return fmt.Sprintf("alive but no turn — auto-kill on idle timeout (pid %d)", pid)
	case "killed":
		return "subprocess no longer alive"
	}
	return "no agent running"
}

